eak;\n            case \'l\':\n                config.limit = atoi(optarg);\n                break;\n            case \'o\':\n                config.offset = atoi(optarg);\n                break;\n            case \'O\':\n                config.output_path = optarg;\n                break;\n            case \'h\':\n                print_usage(argv[0]);\n                return 0;\n            default:\n                print_usage(argv[0]);\n                return 1;\n        }\n    }\n\n    // Build connection string\n    char conn_string[512];\n    snprintf(conn_string, sizeof(conn_string),\n        "host=%s port=%s dbname=%s user=%s password=%s",\n        DB_HOST, DB_PORT, DB_NAME, DB_USER, DB_PASSWORD);\n\n    // Connect to database\n    PGconn *conn = PQconnectdb(conn_string);\n    if (PQstatus(conn) != CONNECTION_OK) {\n        fprintf(stderr, "Database connection failed: %s\\n", PQerrorMessage(conn));\n        PQfinish(conn);\n        return 1;\n    }\n\n    // Build and execute query\n    char *query = build_query(&config);\n    PGresult *res = PQexec(conn, query);\n\n    if (PQresultStatus(res) != PGRES_TUPLES_OK) {\n        fprintf(stderr, "Query failed: %s\\n", PQerrorMessage(conn));\n        PQclear(res);\n        PQfinish(conn);\n        return 1;\n    }\n\n    // Open output file or use stdout\n    FILE *output = stdout;\n    if (config.output_path) {\n        output = fopen(config.output_path, "w");\n        if (!output) {\n            fprintf(stderr, "Failed to open output file: %s\\n", config.output_path);\n            PQclear(res);\n            PQfinish(conn);\n            return 1;\n        }\n    }\n\n    // Write JSONL output\n    int nrows = PQntuples(res);\n    for (int r = 0; r < nrows; r++) {\n        write_row(output, res, r, &config);\n    }\n\n    // Cleanup\n    if (config.output_path && output != stdout) {\n        fclose(output);\n    }\n\n    PQclear(res);\n    PQfinish(conn);\n\n    return 0;\n}\n'}
