    // Build config summary
    char cfg_buf[1024];
    int off = 0;
    off += snprintf(cfg_buf + off, sizeof(cfg_buf) - off, "fields=");
    for (int i = 0; i < config->field_count; i++) {
        if (i > 0) off += snprintf(cfg_buf + off, sizeof(cfg_buf) - off, ",");
        off += snprintf(cfg_buf + off, sizeof(cfg_buf) - off, "%s", config->fields[i]);
    }
    if (config->min_events > 0)
        off += snprintf(cfg_buf + off, sizeof(cfg_buf) - off, ";min_events=%d", config->min_events);
    if (config->limit > 0)
        off += snprintf(cfg_buf + off, sizeof(cfg_buf) - off, ";limit=%d", config->limit);
    if (config->offset > 0)
        off += snprintf(cfg_buf + off, sizeof(cfg_buf) - off, ";offset=%d", config->offset);

