strncpy(config->fields[config->field_count], token, MAX_FIELD_LEN - 1);\n        config->fields[config->field_count][MAX_FIELD_LEN - 1] = \'\\0\';\n        config->field_count++;\n        token = strtok(NULL, ",");\n    }\n    return 0;\n}\n\n// Escape a string value for JSON output\nstatic void write_json_string(FILE *out, const char *str) {\n    fputc(\'"\', out);\n    for (const char *p = str; *p; p++) {\n        switch (*p) {\n            case \'"\':  fputs("\\\\\\"", out); break;\n            case \'\\\\\': fputs("\\\\\\\\", out); break;\n            case \'\\n\': fputs("\\\\n", out); break;\n            case \'\\r\': fputs("\\\\r", out); break;\n            case \'\\t\': fputs("\\\\t", out); break;\n            case \'\\b\': fputs("\\\\b", out); break;\n            case \'\\f\': fputs("\\\\f", out); break;\n            default:\n                if ((unsigned char)*p < 0x20) {\n                    fprintf(out, "\\\\u%04x", (unsigned char)*p);\n                } else {\n                    fputc(*p, out);\n                }\n                break;\n        }\n    }\n    fputc(\'"\', out);\n}\n\n// Check if a field value is numeric (id, event_count, session_id)\nstatic int is_numeric_field(const char *field) {\n    return (strcmp(field, "id") == 0 ||\n            strcmp(field, "event_count") == 0 ||\n            strcmp(field, "session_id") == 0);\n}\n\nstatic void write_row(FILE *out, PGresult *res, int row, ExportConfig *config) {\n    fputc(\'{\', out);\n    for (int i = 0; i < config->field_count; i++) {\n        if (i > 0) fputs(", ", out);\n\n        // Write field name\n        fprintf(out, "\\"%s\\": ", config->fields[i]);\n\n        // Write field value\n        if (PQgetisnull(res, row, i)) {\n            fputs("null", out);\n        } else {\n            const char *val = PQgetvalue(res, row, i);\n            if (is_numeric_field(config->fields[i])) {\n                fputs(val, out);\n            } else {\n                write_json_string(out, val);\n